existants = {r.code for r in db.execute(text("SELECT code FROM points_eau")).fetchall()}
inseres = 0
for p in points:
    if p[0] in existants:
        continue
    db.execute(text("""
        INSERT INTO points_eau (code,nom,type,etat,region,province,commune,latitude,longitude,pop_desservie)
        VALUES (:code,:nom,:type,:etat,:region,:province,:commune,:lat,:lng,:pop)
    """), {'code':p[0],'nom':p[1],'type':p[2],'etat':p[3],'region':p[4],'province':p[5],'commune':p[6],'lat':p[7],'lng':p[8],'pop':p[9]})
    inseres += 1
db.commit()
total = db.execute(text("SELECT COUNT(*) FROM points_eau")).scalar()
print(f"OK — {inseres} inseres, total: {total}")
